local function debug_log(debug_fn, message)
    if debug_fn then debug_fn(message) end
end

local function has_active_mod(mod_name)
    return script and script.active_mods and script.active_mods[mod_name] ~= nil
end

local function get_default_tech_tiers()
    if has_active_mod("space-age") then
        return {
            {"logistic-science-pack"},
            {"chemical-science-pack"},
            {"production-science-pack", "utility-science-pack"},
            {"agricultural-science-pack", "electromagnetic-science-pack", "metallurgic-science-pack"}
        }
    end

    return {
        {"logistic-science-pack"},
        {"chemical-science-pack"},
        {"production-science-pack", "utility-science-pack"},
        {"space-science-pack"}
    }
end

local function get_primary_player_force()
    if not (game and game.forces) then return nil end

    if game.forces["player"] and game.forces["player"].valid then
        return game.forces["player"]
    end

    for force_name, force in pairs(game.forces) do
        if force
            and force.valid
            and force_name ~= "enemy"
            and force_name ~= "neutral"
        then
            return force
        end
    end
end

local function get_tech_only_threat_level(force, tech_tiers)
    local tiers = tech_tiers or get_default_tech_tiers()
    local tiers_total = #tiers
    local tiers_completed = 0

    if force and force.valid then
        for _, tier_opts in ipairs(tiers) do
            local done = false
            for _, pack_name in ipairs(tier_opts) do
                local ok, rec = pcall(function() return force.recipes and force.recipes[pack_name] end)
                if ok and rec and rec.valid and rec.enabled == true then
                    done = true
                    break
                end
            end

            if done then
                tiers_completed = tiers_completed + 1
            end
        end
    end

    local tech = (tiers_total > 0) and (tiers_completed / tiers_total) or 0
    return math.max(0, math.min(1, tech))
end

local function get_blueprint_slot_index_info(index)
    if type(index) == "number" then
        return {
            key = index,
            order = index,
            is_space_age_only = false,
            requires_difficulty_gate = false,
            difficulty_threshold = 0
        }
    end

    if type(index) == "string" then
        local numeric_part, suffix = index:match("^(%d+)([%a_]*)$")
        if numeric_part then
            local normalized_suffix = suffix:lower()
            local is_space_age_only = normalized_suffix == "sa" or normalized_suffix == "sadif" or normalized_suffix == "difsa"
            local requires_difficulty_gate = normalized_suffix == "dif" or normalized_suffix == "sadif" or normalized_suffix == "difsa"

            if normalized_suffix == "" or is_space_age_only or requires_difficulty_gate then
                local order = tonumber(numeric_part)
                local tiers_total = #get_default_tech_tiers()
                local difficulty_threshold = (tiers_total > 0)
                    and math.max(0, math.min(1, order / tiers_total))
                    or 0

                return {
                    key = index,
                    order = order,
                    is_space_age_only = is_space_age_only,
                    requires_difficulty_gate = requires_difficulty_gate,
                    difficulty_threshold = difficulty_threshold
                }
            end
        end
    end
end

local sorted_blueprint_pool_entries_cache = {}

local function get_sorted_blueprint_pool_entries(blueprint_slots)
    local cached_entries = sorted_blueprint_pool_entries_cache[blueprint_slots]
    if cached_entries then
        return cached_entries
    end

    local entries = {}

    for index, blueprint_string in pairs(blueprint_slots) do
        local index_info = get_blueprint_slot_index_info(index)

        if index_info
            and type(blueprint_string) == "string"
            and blueprint_string ~= ""
        then
            entries[#entries + 1] = {
                index_info = index_info,
                blueprint_string = blueprint_string
            }
        end
    end

    table.sort(entries, function(a, b)
        local left = a.index_info
        local right = b.index_info

        if left.order ~= right.order then
            return left.order < right.order
        end

        if left.is_space_age_only ~= right.is_space_age_only then
            return not left.is_space_age_only
        end

        if left.requires_difficulty_gate ~= right.requires_difficulty_gate then
            return not left.requires_difficulty_gate
        end

        return tostring(left.key) < tostring(right.key)
    end)

    sorted_blueprint_pool_entries_cache[blueprint_slots] = entries
    return entries
end

local BLUEPRINT_SOURCES_BY_SHIP = {
    ["pirat_ship_1"] = {
        { source_name = "pirat_ship_1", slots = pirat_ship_1 },
        { source_name = "pirat_ship_2", slots = pirat_ship_2 },
        { source_name = "pirat_ship_3", slots = pirat_ship_3 }
    },
    ["pirat_ship_2"] = {
        { source_name = "pirat_ship_1", slots = pirat_ship_1 },
        { source_name = "pirat_ship_2", slots = pirat_ship_2 },
        { source_name = "pirat_ship_3", slots = pirat_ship_3 }
    },
    ["pirat_ship_3"] = {
        { source_name = "pirat_ship_1", slots = pirat_ship_1 },
        { source_name = "pirat_ship_2", slots = pirat_ship_2 },
        { source_name = "pirat_ship_3", slots = pirat_ship_3 }
    },
    ["pirate_ship_1"] = {
        { source_name = "pirate_ship_1", slots = pirate_ship_1 }
    },
    ["pirate_ship_10"] = {
        { source_name = "pirate_ship_10", slots = pirate_ship_10 }
    }
}

local function is_blueprint_slot_available(index_info, has_space_age, tech_only_threat)
    if index_info.is_space_age_only and not has_space_age then
        return false
    end

    if index_info.requires_difficulty_gate and tech_only_threat < index_info.difficulty_threshold then
        return false
    end

    return true
end

local function is_probably_blueprint_string(value)
    return type(value) == "string" and value ~= "" and value:match("^0eN") ~= nil
end

local function get_blueprint_availability_context()
    local has_space_age = has_active_mod("space-age")
    local force = get_primary_player_force()

    return {
        has_space_age = has_space_age,
        tech_only_threat = get_tech_only_threat_level(force)
    }
end

local function get_available_blueprint_entries(blueprint_sources, availability_context)
    local entries = {}
    local context = availability_context or get_blueprint_availability_context()
    local has_space_age = context.has_space_age
    local tech_only_threat = context.tech_only_threat

    for source_order, source in ipairs(blueprint_sources) do
        local sorted_entries = get_sorted_blueprint_pool_entries(source.slots)

        for _, pool_entry in ipairs(sorted_entries) do
            local index_info = pool_entry.index_info

            if is_probably_blueprint_string(pool_entry.blueprint_string)
                and is_blueprint_slot_available(index_info, has_space_age, tech_only_threat)
            then
                entries[#entries + 1] = {
                    id = tostring(source_order) .. ":" .. tostring(index_info.key),
                    source_name = source.source_name,
                    index_info = index_info,
                    blueprint_string = pool_entry.blueprint_string
                }
            end
        end
    end

    table.sort(entries, function(a, b)
        local left = a.index_info
        local right = b.index_info

        if left.order ~= right.order then
            return left.order < right.order
        end

        if left.is_space_age_only ~= right.is_space_age_only then
            return not left.is_space_age_only
        end

        if left.requires_difficulty_gate ~= right.requires_difficulty_gate then
            return not left.requires_difficulty_gate
        end

        if a.source_name ~= b.source_name then
            return a.source_name < b.source_name
        end

        return tostring(left.key) < tostring(right.key)
    end)

    return entries
end

local function get_available_blueprint_entries_by_ship()
    local availability_context = get_blueprint_availability_context()
    local entries_by_ship = {}

    for name, blueprint_sources in pairs(BLUEPRINT_SOURCES_BY_SHIP) do
        entries_by_ship[name] = get_available_blueprint_entries(blueprint_sources, availability_context)
    end

    return entries_by_ship
end

local function apply_override_to_name(name, blueprint_string, debug_fn)
    local ok, err = pcall(function()
        remote.call("WDM", "add_wdm_blueprint", name, blueprint_string)
    end)

    if ok then
        debug_log(debug_fn, "Applied WDM blueprint override: " .. name)
        return true
    end

    debug_log(debug_fn, "Failed to apply WDM blueprint override '" .. tostring(name) .. "': " .. tostring(err))
    return false
end

local function ensure_override_state()
    storage.wdm_blueprint_override_state = storage.wdm_blueprint_override_state or {}
    local state = storage.wdm_blueprint_override_state
    local entries_by_ship = get_available_blueprint_entries_by_ship()

    for name in pairs(BLUEPRINT_SOURCES_BY_SHIP) do
        local available_entries = entries_by_ship[name]
        local selected_entry_id = state[name]

        if #available_entries == 0 then
            state[name] = nil
        else
            local is_valid = false
            for _, entry in ipairs(available_entries) do
                if selected_entry_id == entry.id then
                    is_valid = true
                    break
                end
            end

            if not is_valid then
                state[name] = available_entries[1].id
            end
        end
    end

    return state
end

local function apply_current_slots(debug_fn)
    if not remote.interfaces["WDM"] then
        debug_log(debug_fn, "WDM interface not found, cannot override WDM blueprints")
        return false
    end

    local state = ensure_override_state()
    local applied = false
    local entries_by_ship = get_available_blueprint_entries_by_ship()

    for name in pairs(BLUEPRINT_SOURCES_BY_SHIP) do
        local selected_entry_id = state[name]
        local selected_entry = nil

        if selected_entry_id then
            for _, entry in ipairs(entries_by_ship[name]) do
                if entry.id == selected_entry_id then
                    selected_entry = entry
                    break
                end
            end
        end

        local blueprint_string = selected_entry and selected_entry.blueprint_string
        if not is_probably_blueprint_string(blueprint_string) then
            debug_log(debug_fn, "No filled WDM blueprint slots for '" .. name .. "', override skipped")
        elseif apply_override_to_name(name, blueprint_string, debug_fn) then
            debug_log(
                debug_fn,
                "Applied WDM blueprint slot #" .. tostring(selected_entry.index_info.key)
                    .. " from '" .. tostring(selected_entry.source_name)
                    .. "' for '" .. name .. "'"
            )
            applied = true
        end
    end

    return applied
end

function M.randomize_wdm_blueprint_overrides(debug_fn)
    local state = ensure_override_state()
    local entries_by_ship = get_available_blueprint_entries_by_ship()

    for name in pairs(BLUEPRINT_SOURCES_BY_SHIP) do
        local available_entries = entries_by_ship[name]
        if #available_entries == 0 then
            state[name] = nil
            debug_log(debug_fn, "No filled WDM blueprint slots available for '" .. name .. "'")
        else
            local selected_entry = available_entries[math.random(1, #available_entries)]
            state[name] = selected_entry.id
            debug_log(
                debug_fn,
                "Selected random WDM blueprint slot #" .. tostring(selected_entry.index_info.key)
                    .. " from '" .. tostring(selected_entry.source_name)
                    .. "' for '" .. name .. "'"
            )
        end
    end

    return state
end

function M.apply_wdm_blueprint_overrides(debug_fn)
    return apply_current_slots(debug_fn)
end

function M.register_wdm_blueprint_overrides(debug_fn)
    M.randomize_wdm_blueprint_overrides(debug_fn)

    return apply_current_slots(debug_fn)
end

return M
